1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote — empty and basic items
6	  it("empty item list yields premium of 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it.todo("a single plain sword yields premium of 115 G (100 base + 10 first insurance + 5 fee)");
14	  it.todo("a single plain amulet yields premium of 71 G (60 + 6 + 5)");
15	  it.todo("a single plain staff yields premium of 93 G (80 + 8 + 5)");
16	  it.todo("a single plain potion yields premium of 49 G (40 + 4 + 5)");
17	
18	  // Components and building blocks
19	  it.todo("a single rune component yields premium of 33 G (25 + 3 + 5)");
20	  it.todo("two runes yield premium of 60 G (50 + 5 + 5)");
21	  it.todo("three alike runes form a block: premium 71 G (60 + 6 + 5)");
22	  it.todo("four runes: no block, premium 115 G (100 + 10 + 5)");
23	  it.todo("two runes + one moonstone: no block, premium 88 G (75 + 7.5→8 + 5)");
24	  it.todo("three runes + three moonstones: two blocks, premium 137 G (120 + 12 + 5)");
25	
26	  // Per-item modifiers
27	  it.todo("a cursed sword (newcomer): premium 165 G");
28	  it.todo("a sword with enchantment 5 adds 30% surcharge");
29	  it.todo("a sword with enchantment 4 adds no surcharge");
30	  it.todo("a cursed sword with enchantment 5 stacks both surcharges");
31	
32	  // Policy-wide modifiers
33	  it.todo("loyalty discount (≥2 years) applies to policy base premium");
34	  it.todo("loyalty discount at exactly 2 years applies");
35	  it.todo("follow-up contract applies 15% discount after first quote");
36	  it.todo("multi-item policy: cursed surcharge applies only to cursed item's base premium");
37	
38	  // Rounding
39	  it.todo("premium rounds up (in MHPCO's favor)");
40	
41	  // Claims — basic
42	  it.todo("standard claim on plain sword: 500 damage → payout 400, cap depletes by 400");
43	  it.todo("claim on rune (no enchantment/material): 200 damage → payout 100");
44	  it.todo("high-enchantment item (≥8): 50% reimbursement, then deductible");
45	  it.todo("dragon-material item: full reimbursement, then deductible");
46	  it.todo("high enchantment + dragon material: 50% rule wins, then deductible");
47	  it.todo("deductible applies per damage entry (multiple items damaged)");
48	
49	  // Cap and multi-item
50	  it.todo("policy cap is 2× insurance sum");
51	  it.todo("two-claim scenario: cap depletes across claims");
52	  it.todo("multiple items of same type: each damage entry has its own deductible");
53	
54	  // Errors
55	  it.todo("unknown item type in quote → CLI exits non-zero");
56	  it.todo("claim references item not on policy → CLI exits non-zero");
57	  it.todo("damage with negative amount → CLI exits non-zero");
58	  it.todo("too many damage entries of a given type → CLI exits non-zero");
59	
60	  // Integration
61	  it.todo("newcomer with cursed sword: 165 G");
62	  it.todo("long-standing customer's second contract with cursed enchanted sword: 160 G");
63	});
